<template>
 <div>
        <client-booking-list v-if="user.is_admin !== 1"></client-booking-list>
   
        <booking-index v-else :bookper="bookper" :clientsetting="clientsetting"></booking-index>
  </div>  
</template>


<script>
import axiosGetPost from '../../helper/axiosGetPostCommon';
export default {
  extends: axiosGetPost,
  data() {
    return {
          user: {},
          bookper: "",
          clientsetting: ""
    };
  },

  methods: {
    getData(route) {
      let instance = this
      this.axiosGet(
        route,
        function (response) {
          console.log(response.data)
          instance.bookper = response.data.bookper
          instance.clientsetting = response.data.clientsetting
          instance.user = response.data.user
        }
      );
    },
  },
  created() {
    this.getData("/bookings");
  },
};
</script>