<template>
  <div>
    <nav-bar
      :profile="user"
      services="1"
      booking="1"
      userroles="1"
      usermanage="1"
      appsettings="1"
      emailsettings="1"
      offdaysettings="1"
      holidaysettings="1"
      emailtemplate="1"
      clientmanage="1"
      clientsetting="1"
      reportpermission="1"
    >
    </nav-bar>

    <side-bar
      :route="$route.path.split('/')[1]"
      :routeurl="$route.path"
      services="1"
      booking="1"
      userroles="1"
      usermanage="1"
      appsettings="1"
      emailsettings="1"
      offdaysettings="1"
      holidaysettings="1"
      emailtemplate="1"
      clientmanage="1"
      clientsetting="1"
      reportpermission="1"
    >
    </side-bar>

    <router-view></router-view>
  </div>
</template>

<script>
import axiosGetPost from "./../helper/axiosGetPostCommon";

export default {
  extends: axiosGetPost,
  data() {
    return {
      signupCheck: {},
      user: {},
      service: false,
      copyrightText: "",
      landingPageMessage: "",
      landingPageHeader: "",
    };
  },

  methods: {
    getData(route) {
      let instance = this;
      this.axiosGet(route, function (response) {
        //console.log(response.data.copyright_text);
        instance.signupCheck = response.data.signupCheck;
        instance.user = response.data.user;
        instance.service = response.data.service;
        instance.copyrightText = response.data.copyright_text;
        instance.landingPageMessage = response.data.landingPageMessage;
        instance.landingPageHeader = response.data.landingPageHeader;
      });
    },
  },
  created() {
    this.getData("/homepage");
  },
};
</script>        