<template>
  <salon_component
    :landing_page_header="landingPageMessage"
    :landing_page_message="landingPageMessage"
    :copyright_text="copyrightText"
    :checksignup="signupCheck"
    :service="service"
    :user="user"
  >
  </salon_component>
</template>


<script>
import axiosGetPost from '../../helper/axiosGetPostCommon';
import salon_component from "./SalonIndex.vue";

export default {
  extends: axiosGetPost,
  components: {
    salon_component,
  },
  data() {
    return {
          signupCheck: {},
          user: {},
          service: false,
          copyrightText: "",
          landingPageMessage: "",
          landingPageHeader: ""
      
    };
  },

  methods: {
    getData(route) {
      let instance = this
      this.axiosGet(
        route,
        function (response) {
          console.log(response.data)
          instance.currentBranch = response.data.currentBranch
          instance.signupCheck = response.data.signupCheck,
          instance.user = response.data.user,
          instance.service = response.data.service,
          instance.copyrightText = response.data.copyright_text,
          instance.landingPageMessage = response.data.landingPageMessage,
          instance.landingPageHeader = response.data.landingPageHeader
        }
      );
    },
  },
  created() {
    this.getData("/homepage");
  },
};
</script>