import home from './components/salonLanding';
import Login from './components/auth/Login';
import register from './components/auth/Register';
import services from './components/service/indexAll.vue';
import bookings from './components/booking/index.vue';
import bookingDetails from './components/booking/View.vue';
import clients from './components/Clients/Index.vue';
import reports from './components/reports/Reports.vue';
import settings from './components/setting/indexAll.vue';
import myprofile from './components/users/ProfileIndex';
import Dashboard from './components/Dashboard/Dashboard.vue';


import LayoutA from './layouts/LayoutA';
import LayoutB from './layouts/LayoutB';

import Vue from 'vue'
import VueRouter from 'vue-router'
Vue.use(VueRouter)

const routes = [        {
    path: '/login',
    component: Login,
    name: "Login",
    meta: { layout: LayoutB }
}, 
{
    path: '/register',
    component: register,
    name: "register",
    meta: { layout: LayoutB }
},
{
    path: '/',
    component: home,
    name: "salonLanding",
    meta: { layout: LayoutB }
},

{
    path: '/dashboard',
    component: Dashboard,
    name: "dashboard",
    meta: { layout: LayoutA },
    /* beforeEnter: (to, form, next) =>{

        axios.defaults.headers.common['Authorization'] = `Bearer ${localStorage.getItem("token")}` 
        axios.get(window.appConfig.appUrl + '/athenticated').then(()=>{
            next()
        }).catch(()=>{
            return next({ name: 'Login'})
        })
    } */
},

{
    path: '/services',
    component: services,
    name: "services",
    meta: { layout: LayoutA }
},

{
    path: '/bookings',
    component: bookings,
    name: "bookings",
    meta: { layout: LayoutA }
},

{
    path: '/booking-details/:id',
    component: bookingDetails,
    name: "bookingDetails",
    meta: { layout: LayoutA }
},

{
    path: '/clients',
    component: clients,
    name: "clients",
    meta: { layout: LayoutA }
},

{
    path: '/reports',
    component: reports,
    name: "reports",
    meta: { layout: LayoutA }
},

{
    path: '/myprofile',
    component: myprofile,
    name: "myprofile",
    meta: { layout: LayoutA }
},

{
    path: '/settings',
    component: settings,
    name: "settings",
    props: true,
    meta: { layout: LayoutA }
},

]

const router = new VueRouter({
base: '/',
mode: 'history',
routes
})

export default router

