<template>
  <div class="side-bar">
    <ul>
      <li class="side-bar-logo">
        <a
          href="#"
          @click="dashboardclick"
        >
          <img
            :src="publicPath + '/uploads/logo/' + appLogo"
            alt=""
          />
        </a>
      </li>
      <li :class="{ 'active-side-bar': route == 'dashboard' }">
        <a
          href="#"
          @click="dashboardclick"
        >
          <i class="la la-desktop la-3x"></i>
          <div>{{ trans("lang.dashboard") }}</div>
        </a>
      </li>
      <li
        v-if="services == 1"
        :class="{ 'active-side-bar': route == 'services' }"
      >
        <a
          href="#"
          @click="servicesclick"
        >
          <i class="la la-globe"></i>
          <div>{{ trans("lang.services") }}</div>
        </a>
      </li>
      <li
        v-if="booking == 1"
        :class="{
          'active-side-bar':
            route == 'bookings' || routeurl.search('booking-details') > -1,
        }"
      >
        <a
          href="#"
          @click="bookingsclick"
        >
          <i class="la la-credit-card"></i>
          <div>{{ trans("lang.bookings") }}</div>
        </a>
      </li>
      <li
        v-if="clientmanage == 1"
        :class="{
          'active-side-bar':
            route == 'clients' || routeurl.search('client') > -1,
        }"
      >
        <a
          href="#"
          @click="clientsclick"
        >
          <i class="la la-users"></i>
          <div>{{ trans("lang.clients") }}</div>
        </a>
      </li>
      <li
        v-if="reportpermission == 1"
        :class="{ 'active-side-bar': route == 'reports' }"
      >
        <a
          href="#"
          @click="reportsclick"
        >
          <i class="la la-pie-chart"></i>
          <div>{{ trans("lang.reports") }}</div>
        </a>
      </li>
      <li
        v-if="
          userroles == 1 ||
          usermanage == 1 ||
          appsettings == 1 ||
          emailsettings == 1 ||
          offdaysettings == 1 ||
          holidaysettings == 1 ||
          emailtemplate == 1 ||
          clientsetting == 1
        "
        :class="{
          'active-side-bar':
            route == 'settings' || routeurl.search('/user') > -1,
        }"
      >
        <a
          href="#"
          @click="settingsclick"
        >
          <i class="la la-cogs la-3x"></i>
          <div>{{ trans("lang.settings") }}</div>
        </a>
      </li>
    </ul>
  </div>
</template>

<script>
import axiosGetPost from "../../helper/axiosGetPostCommon";
export default {
  extends: axiosGetPost,
  props: [
    "route",
    "routeurl",
    "services",
    "booking",
    "userroles",
    "usermanage",
    "appsettings",
    "emailsettings",
    "offdaysettings",
    "holidaysettings",
    "emailtemplate",
    "clientmanage",
    "reportpermission",
    "clientsetting",
  ],

  methods: {
    dashboardclick() {
      let instance = this;
      //instance.redirect("/dashboard");
      this.$router.push({ name: "dashboard", params: {} });
    },
    servicesclick() {
      let instance = this;
      //instance.redirect("/services");
      this.$router.push({ name: "services", params: {} });
    },
    bookingsclick() {
      let instance = this;
      //instance.redirect("/bookings");
      this.$router.push({ name: "bookings", params: {} });
    },
    clientsclick() {
      let instance = this;
      //instance.redirect("/clients");
      this.$router.push({ name: "clients", params: {} });
    },
    reportsclick() {
      let instance = this;
      //instance.redirect("/reports");
      this.$router.push({ name: "reports", params: {} });
    },
    settingsclick() {
      let instance = this;
      console.log(instance.settingsData);
      this.$router.push({ name: "settings", params: instance.settingsData });
    },

    getSettingsData(route) {
      //extra
      this.axiosGet(route, function (response) {
        this.settingsData.roles = response.data.roles;
        this.settingsData.users = response.data.users;
        this.settingsData.app_settings = response.data.app_settings;
        this.settingsData.email_settings = response.data.email_settings;
        this.settingsData.sms_settings = response.data.sms_settings;
        this.settingsData.sms_templates = response.data.sms_templates;
        this.settingsData.off_day = response.data.off_day;
        this.settingsData.holiday = response.data.holiday;
        this.settingsData.break_time = response.data.break_time;
        this.settingsData.email_templates = response.data.email_templates;
        this.settingsData.client_settings = response.data.client_settings;
        this.settingsData.payment_settings = response.data.payment_settings;
        this.settingsData.custom_input_settings =
          response.data.custom_input_settings;
        this.settingsData.service_policy = response.data.service_policy;
        this.settingsData.social_link = response.data.social_link;
        this.settingsData.contact_information =
          response.data.contact_information;
        this.settingsData.updates = response.data.updates;
        this.settingsData.all_time_zone = response.data.all_time_zone;
      });
    },
  },
  data() {
    return {
      settingsData: {
        roles: 0,
        users: 1,
        app_settings: 1,
        email_settings: 1,
        sms_settings: 1,
        sms_templates: 1,
        off_day: 1,
        holiday: 1,
        break_time: 1,
        email_templates: 1,
        client_settings: 1,
        payment_settings: 1,
        custom_input_settings: 1,
        service_policy: 1,
        social_link: 1,
        contact_information: 1,
        updates: 1,
        all_time_zone: "[]",
      },
    };
  },
  created() {
    this.getSettingsData("/settings");
  },
};
</script>