<template>
  <div>
    <setting-index
      :roles="settingsData.roles"
      :users="settingsData.user"
      :app_settings="settingsData.app_settings"
      :email_settings="settingsData.email_settings"
      :sms_settings="settingsData.sms_settings"
      :sms_templates="settingsData.sms_templates"
      :off_day="settingsData.off_day"
      :holiday="settingsData.holiday"
      :break_time="settingsData.break_time"
      :email_templates="settingsData.email_templates"
      :client_settings="settingsData.client_settings"
      :payment_settings="settingsData.payment_settings"
      :custom_input_settings="settingsData.custom_input_settings"
      :service_policy="settingsData.service_policy"
      :social_link="settingsData.social_link"
      :contact_information="settingsData.contact_information"
      :updates="settingsData.updates"
      :all_time_zone="settingsData.all_time_zone"
    ></setting-index>
  </div>
</template>



<script>
import axiosGetPost from "../../helper/axiosGetPostCommon";
//import salesReceives from "./SalesOrPurchase.vue";

export default {
  extends: axiosGetPost,
  props: [],
  /*   components: {
    salesReceives,
  }, */
  data() {
    return {
      settingsData: {
        roles: 0,
        users: 1,
        app_settings: 1,
        email_settings: 1,
        sms_settings: 1,
        sms_templates: 1,
        off_day: 1,
        holiday: 1,
        break_time: 1,
        email_templates: 1,
        client_settings: 1,
        payment_settings: 1,
        custom_input_settings: 1,
        service_policy: 1,
        social_link: 1,
        contact_information: 1,
        updates: 1,
        all_time_zone: "[]",
      },
    };
  },

  methods: {
    getSettingsData(route) {
      //extra
      this.axiosGet(route, function (response) {
        this.settingsData.roles = response.data.roles;
        this.settingsData.users = response.data.users;
        this.settingsData.app_settings = response.data.app_settings;
        this.settingsData.email_settings = response.data.email_settings;
        this.settingsData.sms_settings = response.data.sms_settings;
        this.settingsData.sms_templates = response.data.sms_templates;
        this.settingsData.off_day = response.data.off_day;
        this.settingsData.holiday = response.data.holiday;
        this.settingsData.break_time = response.data.break_time;
        this.settingsData.email_templates = response.data.email_templates;
        this.settingsData.client_settings = response.data.client_settings;
        this.settingsData.payment_settings = response.data.payment_settings;
        this.settingsData.custom_input_settings =
          response.data.custom_input_settings;
        this.settingsData.service_policy = response.data.service_policy;
        this.settingsData.social_link = response.data.social_link;
        this.settingsData.contact_information =
          response.data.contact_information;
        this.settingsData.updates = response.data.updates;
        this.settingsData.all_time_zone = response.data.all_time_zone;
      });
    },
  },
  created() {
    this.getSettingsData("/settings");
  },
};
</script>