//extra
Vue.mixin({
	methods: {
		uploadImageHelper: function(input, path, uploadDirectory) {
			var formData = new FormData();
			var name = input.files[0];

			if (window.location.href.indexOf('localhost' | '127.0.0.1') > -1) {
				console.log('localhost works...');
				const file = new File([ name ], { type: name.type });
				console.log(name);
				var xhr = new XMLHttpRequest();
				xhr.open('PUT', uploadDirectory + name.name, true);
				xhr.send(file);
			} else {
				if (!name.type.match('image.*')) {
					//statusP.innerHTML = "The name selected is not an image.";
					return;
				}

				formData.append('fileAjax', name, name.name);
				formData.append('uploadDirectory', uploadDirectory);

				var xhr = new XMLHttpRequest();

				xhr.open('POST', path, true);

				xhr.onload = function() {
					if (xhr.status == 200) {
						//statusP.innerHTML = "Upload copmlete!";
					} else {
						//statusP.innerHTML = "Upload error. Try again.";
					}
				};

				xhr.send(formData);
			}
		}
	}
});

